--
-- Table structure for table `course_credit_settings`
--

DROP TABLE IF EXISTS `course_credit_settings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `course_credit_settings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `degree_program_id` bigint unsigned NOT NULL,
  `course_credit_unit` smallint unsigned NOT NULL,
  `gov_doc_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `start_year` smallint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
